class UserModel implements User {
  id: number;
  name: string;
  email: string;
  isActive: boolean;

  constructor(id: number, name: string, email: string, isActive = true) {
    this.id = id;
    this.name = name;
    this.email = email;
    this.isActive = isActive;
  }

  deactivate() {
    this.isActive = false;
  }

  isEmailValid(): boolean {
    return /^\S+@\S+\.\S+$/.test(this.email);
  }
